import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Dynamically allocate memory for the buffer based on user input length
        byte[] buffer = new byte[input.length()];

        // Copy the user input into the buffer
        for (int i = 0; i < input.length(); i++) {
            buffer[i] = (byte) input.charAt(i);
        }

        System.out.println("Input successfully stored in buffer.");
    }
}

